<script>
import gsap from "gsap";
import p5 from "p5";

var cont1val = 0;
var cont2val = 0;
var p4vsible = false;

let sketchP3 = (sk) => {
  var lastPos = {};
  var posArr = [];
  const rStep = 40;
  const n = 20;
  var noiseFactor = { x: 10 };
  var controlContainer = document.querySelector("#svgContainer");

  sk.setup = () => {
    sk.createCanvas(
      controlContainer.clientWidth,
      controlContainer.clientHeight
    ).parent("svgContainer");
    lastPos = { x: sk.width / 2, y: sk.height / 2 };
    let arrCount = 0;
    while (arrCount < n) {
      arrCount++;
      posArr.push({ x: sk.width / 2, y: sk.height / 2 });
    }
    let canvas = document.querySelector(".p5Canvas");
    let invisibleCanvas = document.querySelector(".hoveranusCanvasus");
    invisibleCanvas.addEventListener("pointermove", (e) => {
      gsap.to(posArr, { x: sk.mouseX, y: sk.mouseY, stagger: 0.02 });
      gsap.fromTo(noiseFactor, { x: 0 }, { x: 10, duration: 0.2 });
    });
    sk.angleMode(sk.DEGREES);
    sk.colorMode(sk.HSB);
  };

  sk.draw = () => {
    sk.background("#020605");
    let count = n;
    while (count > 1) {
      count--;
      sk.push();
      sk.translate(posArr[count].x, posArr[count].y);
      createCircle(rStep * count);
      sk.pop();
    }
    function createCircle(radius) {
      let bStep = 10;
      let bounce = sk.map(
        sk.cos(sk.mouseX + sk.mouseY) * bStep,
        -bStep,
        bStep,
        2,
        10
      );
      sk.stroke(260, 60, sk.map(radius, 30, 300, 70, 100));
      sk.fill(264, 85, sk.map(radius, 30, 300, 12, 98));
      sk.beginShape();
      for (let i = 0; i < 359; i++) {
        let R1 = sk.map(
          sk.sin(i * radius + sk.frameCount * 6),
          -1,
          1,
          radius - bounce,
          radius
        );
        let R2 = sk.map(
          sk.cos((i * radius) / 2 + sk.frameCount * 6),
          -1,
          1,
          radius - bounce,
          radius
        );
        let R = R1 + R2;
        sk.vertex(R * sk.cos(i), R * sk.sin(i));
      }
      sk.endShape(sk.CLOSE);
    }
  };
};

export default {
  name: "p3-p4",
  components: {},
  data() {
    return {
      P5P3: null,
      cont1val: null,
      cont2val: null,
      p4visible: false,
      activeSector: null,
    };
  },
  mounted() {
    // Отправляем BroadcastChannel при загрузке p3-p4
    const channel = new BroadcastChannel("page-load");
    channel.postMessage(3);
    this.P5P3 = new p5(sketchP3);

    this.setupP3Canvas();

    gsap.to("#light", {
      ease: "none",
      duration: 10,
      rotation: 360,
      repeat: -1,
    });
    gsap.to("#lightA", {
      ease: "none",
      duration: 12,
      rotation: -360,
      repeat: -1,
    });
    gsap.to("#light2", {
      ease: "none",
      duration: 10,
      rotation: 360,
      repeat: -1,
    });
    gsap.to("#lightA2", {
      ease: "none",
      duration: 12,
      rotation: -360,
      repeat: -1,
    });
  },
  methods: {
    setupP3Canvas() {
      var hoveranus = new Image();
      hoveranus.src = "/hoveranus.jpg";
      var hoveranusCanvasus, ctx;

      hoveranusCanvasus = document.querySelector(".hoveranusCanvasus");
      ctx = hoveranusCanvasus.getContext("2d");

      hoveranusCanvasus.width = hoveranusCanvasus.clientWidth;
      hoveranusCanvasus.height = hoveranusCanvasus.clientHeight;

      hoveranus.onload = function () {
        ctx.drawImage(
          hoveranus,
          0,
          0,
          hoveranusCanvasus.width,
          hoveranusCanvasus.height
        );
        hoveranus.style.display = "none";
      };

      function pick(event) {
        var x = event.layerX;
        var y = event.layerY;
        var pixel = ctx.getImageData(x, y, 1, 1);
        var data = pixel.data;
        let number = Math.round(data[0] + data[1] + data[2]);
        if (number == 336) {
          cont1val = 1;
        }
        if (number == 344) {
          cont1val = 2;
        }
        if (number == 502) {
          cont1val = 3;
        }
        if (number == 254) {
          cont1val = 4;
        }
        if (number == 0) {
          cont1val = 5;
        }
        if (number == 765) {
          cont1val = 6;
        }
      }
      hoveranusCanvasus.addEventListener("mousemove", pick);
    },
    onSectorClick(sectorNumber) {
      cont2val = sectorNumber;
      this.activeSector = sectorNumber;
    },
    toggleView(direction) {
      if (direction === "next") {
        // Скрыть p3 элементы
        gsap.to(".p3", {
          opacity: 0,
          duration: 0.6,
          ease: "power2.inOut",
          pointerEvents: "none",
        });
        // Показать p4 элементы
        gsap.to(".p4", {
          opacity: 1,
          duration: 0.6,
          ease: "power2.inOut",
          pointerEvents: "auto",
        });
        this.p4visible = true;
      } else if (direction === "prev") {
        // Показать p3 элементы
        gsap.to(".p3", {
          opacity: 1,
          duration: 0.6,
          ease: "power2.inOut",
          pointerEvents: "auto",
        });
        // Скрыть p4 элементы
        gsap.to(".p4", {
          opacity: 0,
          duration: 0.6,
          ease: "power2.inOut",
          pointerEvents: "none",
        });
        this.p4visible = false;
      }
    },
  },
  beforeUnmount() {
    if (this.P5P3) {
      this.P5P3.remove();
    }
  },
};
</script>

